import React, { useState, useRef, useMemo, useCallback, useEffect } from 'react';

const theme = {
  bg: '#0a0a0a', surface: '#141414', card: '#1a1a1a', border: '#2a2a2a',
  text: '#fafafa', muted: '#a1a1aa', dim: '#52525b',
  blue: '#38bdf8', pink: '#f472b6', green: '#4ade80', yellow: '#fbbf24',
  purple: '#a78bfa',
};

const presets = [
  { name: 'Mirrored', p: [0.1, 0.2, 0.3, 0.4], q: [0.4, 0.3, 0.2, 0.1] },
  { name: 'Identical', p: [0.25, 0.25, 0.25, 0.25], q: [0.25, 0.25, 0.25, 0.25] },
  { name: 'Opposite', p: [0.01, 0.01, 0.01, 0.97], q: [0.97, 0.01, 0.01, 0.01] },
  { name: 'Similar', p: [0.2, 0.3, 0.3, 0.2], q: [0.25, 0.25, 0.25, 0.25] },
];

const labels = ['x1', 'x2', 'x3', 'x4'];

export default function App() {
  const [p, setP] = useState([...presets[0].p]);
  const [q, setQ] = useState([...presets[0].q]);
  const [dragging, setDragging] = useState(null);
  const [hoveredBar, setHoveredBar] = useState(null);
  const svgRef = useRef(null);

  const sqrtPQ = useMemo(() => p.map((pi, i) => Math.sqrt(pi * q[i])), [p, q]);
  const bc = useMemo(() => sqrtPQ.reduce((s, v) => s + v, 0), [sqrtPQ]);
  const bd = useMemo(() => (bc > 0 && bc < 1) ? -Math.log(bc) : (bc >= 1 ? 0 : 999), [bc]);

  const chartW = 540, chartH = 210;
  const pad = { top: 15, right: 20, bottom: 32, left: 42 };
  const plotW = chartW - pad.left - pad.right;
  const plotH = chartH - pad.top - pad.bottom;

  const rawMax = Math.max(...p, ...q);
  const maxVal = Math.max(0.5, Math.ceil(rawMax * 5) / 5);
  const yScale = (v) => pad.top + plotH * (1 - v / maxVal);
  const barH = (v) => plotH * (v / maxVal);

  const groupW = plotW / 4;
  const bw = groupW * 0.28;
  const gap = groupW * 0.06;

  const getBarX = (gi, di) => {
    const gs = pad.left + gi * groupW + (groupW - 2 * bw - gap) / 2;
    return gs + di * (bw + gap);
  };

  const redistribute = useCallback((arr, idx, newVal) => {
    const clamped = Math.max(0.01, Math.min(0.96, newVal));
    const next = [...arr];
    next[idx] = clamped;
    const remaining = 1 - clamped;
    const otherSum = next.reduce((s, v, i) => i === idx ? s : s + v, 0);
    if (otherSum > 0.001) {
      const scale = remaining / otherSum;
      for (let i = 0; i < next.length; i++) {
        if (i !== idx) next[i] = Math.max(0.005, next[i] * scale);
      }
    } else {
      const each = remaining / (next.length - 1);
      for (let i = 0; i < next.length; i++) {
        if (i !== idx) next[i] = each;
      }
    }
    const sum = next.reduce((s, v) => s + v, 0);
    for (let i = 0; i < next.length; i++) next[i] /= sum;
    return next;
  }, []);

  const handleMouseDown = useCallback((dist, idx, e) => {
    e.preventDefault();
    setDragging({ dist, idx });
  }, []);

  const handleMouseMove = useCallback((e) => {
    if (!dragging || !svgRef.current) return;
    const svg = svgRef.current;
    const rect = svg.getBoundingClientRect();
    const svgY = (e.clientY - rect.top) * (chartH / rect.height);
    const rawVal = (1 - (svgY - pad.top) / plotH) * maxVal;
    const setter = dragging.dist === 'p' ? setP : setQ;
    const current = dragging.dist === 'p' ? p : q;
    setter(redistribute(current, dragging.idx, rawVal));
  }, [dragging, p, q, maxVal, plotH, chartH, pad.top, redistribute]);

  const handleMouseUp = useCallback(() => {
    setDragging(null);
  }, []);

  useEffect(() => {
    if (dragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
      return () => {
        window.removeEventListener('mousemove', handleMouseMove);
        window.removeEventListener('mouseup', handleMouseUp);
      };
    }
  }, [dragging, handleMouseMove, handleMouseUp]);

  const fmt = (v) => v.toFixed(2);
  const fmt3 = (v) => v.toFixed(3);
  const fmt4 = (v) => v.toFixed(4);

  const getInsight = () => {
    if (bd < 0.001) return { text: 'Distributions are identical. BC = 1 means perfect overlap, so distance = 0.', color: theme.green };
    if (bd < 0.05) return { text: 'Very similar distributions. High overlap keeps the distance near zero.', color: theme.green };
    if (bd < 0.2) return { text: 'Moderate similarity. Some divergence reduces the Bhattacharyya coefficient.', color: theme.yellow };
    if (bd < 0.6) return { text: 'Noticeable difference. The overlap between P and Q is limited.', color: theme.yellow };
    if (bd < 1.5) return { text: 'Very different distributions. Low overlap means high distance.', color: theme.pink };
    return { text: 'Extremely different. Almost no overlap between P and Q.', color: theme.pink };
  };

  const insight = getInsight();

  const yTicks = [];
  for (let v = 0; v <= maxVal + 0.001; v += maxVal <= 0.5 ? 0.1 : 0.2) {
    yTicks.push(v);
  }

  return (
    <div style={{ minHeight: '100vh', background: theme.bg, color: theme.text, fontFamily: "'Inter', system-ui, sans-serif", display: 'flex', flexDirection: 'column', alignItems: 'center', padding: '16px 12px' }}>
      <div style={{ width: '100%', maxWidth: 580 }}>

        <div style={{ marginBottom: 14 }}>
          <h1 style={{ fontSize: 18, fontWeight: 700, margin: 0, marginBottom: 4 }}>Bhattacharyya Distance</h1>
          <p style={{ fontSize: 11, color: theme.dim, margin: 0 }}>Drag bars to reshape distributions P and Q. Watch the distance change.</p>
        </div>

        <div style={{ display: 'flex', gap: 6, marginBottom: 14, flexWrap: 'wrap' }}>
          {presets.map((pr, i) => (
            <button key={i} onClick={() => { setP([...pr.p]); setQ([...pr.q]); }} style={{
              background: theme.card, border: '1px solid ' + theme.border, borderRadius: 6,
              color: theme.muted, fontSize: 11, padding: '5px 10px', cursor: 'pointer',
              transition: 'all 0.2s',
            }}
            onMouseEnter={(e) => { e.target.style.borderColor = theme.purple; e.target.style.color = theme.text; }}
            onMouseLeave={(e) => { e.target.style.borderColor = theme.border; e.target.style.color = theme.muted; }}
            >{pr.name}</button>
          ))}
        </div>

        <div style={{ background: theme.surface, borderRadius: 12, border: '1px solid ' + theme.border, padding: '12px 8px 8px', marginBottom: 14 }}>
          <div style={{ display: 'flex', gap: 16, marginBottom: 8, marginLeft: 8 }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: 5, fontSize: 11 }}>
              <div style={{ width: 10, height: 10, borderRadius: 2, background: theme.blue, opacity: 0.8 }} />
              <span style={{ color: theme.muted }}>P(x)</span>
            </div>
            <div style={{ display: 'flex', alignItems: 'center', gap: 5, fontSize: 11 }}>
              <div style={{ width: 10, height: 10, borderRadius: 2, background: theme.pink, opacity: 0.8 }} />
              <span style={{ color: theme.muted }}>Q(x)</span>
            </div>
          </div>

          <svg ref={svgRef} viewBox={`0 0 ${chartW} ${chartH}`} style={{ width: '100%', display: 'block', cursor: dragging ? 'ns-resize' : 'default' }}>
            {yTicks.map((v, i) => (
              <g key={i}>
                <line x1={pad.left} y1={yScale(v)} x2={chartW - pad.right} y2={yScale(v)} stroke={theme.border} strokeWidth={0.5} />
                <text x={pad.left - 6} y={yScale(v) + 3} textAnchor="end" fill={theme.dim} fontSize={9} fontFamily="monospace">{v.toFixed(1)}</text>
              </g>
            ))}

            <line x1={pad.left} y1={yScale(0)} x2={chartW - pad.right} y2={yScale(0)} stroke={theme.border} strokeWidth={1} />

            {[0, 1, 2, 3].map(gi => {
              const pX = getBarX(gi, 0);
              const qX = getBarX(gi, 1);
              const pH = barH(p[gi]);
              const qH = barH(q[gi]);
              const pY = yScale(p[gi]);
              const qY = yScale(q[gi]);
              const isHovP = hoveredBar && hoveredBar.dist === 'p' && hoveredBar.idx === gi;
              const isHovQ = hoveredBar && hoveredBar.dist === 'q' && hoveredBar.idx === gi;
              const isDragP = dragging && dragging.dist === 'p' && dragging.idx === gi;
              const isDragQ = dragging && dragging.dist === 'q' && dragging.idx === gi;

              return (
                <g key={gi}>
                  <rect x={pX} y={pY} width={bw} height={pH} rx={3}
                    fill={theme.blue} opacity={isDragP ? 0.95 : isHovP ? 0.85 : 0.65}
                    style={{ cursor: 'ns-resize', transition: dragging ? 'none' : 'all 0.25s ease' }}
                    onMouseDown={(e) => handleMouseDown('p', gi, e)}
                    onMouseEnter={() => setHoveredBar({ dist: 'p', idx: gi })}
                    onMouseLeave={() => setHoveredBar(null)}
                  />
                  <rect x={qX} y={qY} width={bw} height={qH} rx={3}
                    fill={theme.pink} opacity={isDragQ ? 0.95 : isHovQ ? 0.85 : 0.65}
                    style={{ cursor: 'ns-resize', transition: dragging ? 'none' : 'all 0.25s ease' }}
                    onMouseDown={(e) => handleMouseDown('q', gi, e)}
                    onMouseEnter={() => setHoveredBar({ dist: 'q', idx: gi })}
                    onMouseLeave={() => setHoveredBar(null)}
                  />

                  {(isHovP || isDragP) && (
                    <text x={pX + bw / 2} y={pY - 5} textAnchor="middle" fill={theme.blue} fontSize={10} fontWeight={600} fontFamily="monospace">{fmt(p[gi])}</text>
                  )}
                  {(isHovQ || isDragQ) && (
                    <text x={qX + bw / 2} y={qY - 5} textAnchor="middle" fill={theme.pink} fontSize={10} fontWeight={600} fontFamily="monospace">{fmt(q[gi])}</text>
                  )}

                  <text x={pad.left + gi * groupW + groupW / 2} y={chartH - 8} textAnchor="middle" fill={theme.dim} fontSize={11} fontFamily="monospace">{labels[gi]}</text>
                </g>
              );
            })}
          </svg>
        </div>

        <div style={{ background: theme.surface, borderRadius: 12, border: '1px solid ' + theme.border, padding: 14, marginBottom: 14 }}>
          <div style={{ fontSize: 11, color: theme.dim, marginBottom: 10, fontWeight: 600, letterSpacing: 0.5 }}>COMPUTATION</div>

          <div style={{ display: 'flex', gap: 6, marginBottom: 12, justifyContent: 'center', alignItems: 'center', flexWrap: 'wrap' }}>
            {[0, 1, 2, 3].map((i) => (
              <React.Fragment key={i}>
                <div style={{
                  background: theme.card, borderRadius: 8, padding: '8px 10px', textAlign: 'center',
                  border: '1px solid ' + theme.border, minWidth: 80,
                  transition: 'all 0.3s ease',
                }}>
                  <div style={{ fontSize: 9, color: theme.dim, marginBottom: 3, fontFamily: 'monospace' }}>
                    sqrt(<span style={{ color: theme.blue }}>{fmt(p[i])}</span> * <span style={{ color: theme.pink }}>{fmt(q[i])}</span>)
                  </div>
                  <div style={{ fontSize: 14, fontWeight: 700, color: theme.green, fontFamily: 'monospace', transition: 'all 0.3s ease' }}>
                    {fmt3(sqrtPQ[i])}
                  </div>
                </div>
                {i < 3 && <span style={{ color: theme.dim, fontSize: 14, fontWeight: 600 }}>+</span>}
              </React.Fragment>
            ))}
          </div>

          <div style={{ display: 'flex', justifyContent: 'center', gap: 24, alignItems: 'center', flexWrap: 'wrap' }}>
            <div style={{ textAlign: 'center' }}>
              <div style={{ fontSize: 10, color: theme.dim, marginBottom: 3 }}>BC (coefficient)</div>
              <div style={{ fontSize: 20, fontWeight: 700, color: theme.green, fontFamily: 'monospace', transition: 'all 0.3s ease' }}>{fmt4(bc)}</div>
              <div style={{ width: 120, height: 4, background: theme.card, borderRadius: 2, marginTop: 6, overflow: 'hidden' }}>
                <div style={{ width: (Math.min(1, bc) * 100) + '%', height: '100%', background: theme.green, borderRadius: 2, transition: 'width 0.3s ease' }} />
              </div>
            </div>

            <div style={{ color: theme.dim, fontSize: 18 }}>=></div>

            <div style={{ textAlign: 'center' }}>
              <div style={{ fontSize: 10, color: theme.dim, marginBottom: 3 }}>BD = -ln(BC)</div>
              <div style={{ fontSize: 24, fontWeight: 800, fontFamily: 'monospace', transition: 'all 0.3s ease', color: bd < 0.05 ? theme.green : bd < 0.3 ? theme.yellow : theme.pink }}>
                {bd > 100 ? 'Inf' : fmt4(bd)}
              </div>
            </div>
          </div>
        </div>

        <div style={{
          fontSize: 12, color: insight.color, lineHeight: 1.6,
          borderLeft: '3px solid ' + insight.color, paddingLeft: 12,
          transition: 'all 0.3s ease', opacity: 0.9,
        }}>
          {insight.text}
        </div>

      </div>
    </div>
  );
}
